1	package config
2	
3	import (
4		"fmt"
5		"os"
6		"runtime"
7		"strings"
8	
9		"gopkg.in/yaml.v3"
10	)
11	
12	const LocalAddr = "local"
13	
14	func IsLocalAddr(addr string) bool {
15		return strings.EqualFold(strings.TrimSpace(addr), LocalAddr)
16	}
17	
18	type Config struct {
19		GitHub  GitHubConfig          `yaml:"github"`
20		Hosts   map[string]HostConfig `yaml:"hosts"`
21		Runners []RunnerConfig        `yaml:"runners"`
22	}
23	
24	type GitHubConfig struct {
25		PAT string `yaml:"pat"`
26	}
27	
28	type HostConfig struct {
29		Addr         string `yaml:"addr"`
30		OS           string `yaml:"os"`
31		Arch         string `yaml:"arch"`
32		WindowsPS    string `yaml:"windows_ps"`    // powershell (default) or pwsh — which exe runs encoded remote scripts on Windows
33		DockerSocket string `yaml:"docker_socket"` // override Docker socket path (Linux/macOS; if empty, gh sr probes default path, docker context, then Colima default on macOS)
34	}
35	
36	type RunnerConfig struct {
37		Name              string   `yaml:"name"`
38		Repo              string   `yaml:"repo"`
39		Org               string   `yaml:"org"`
40		Group             string   `yaml:"group"`
41		Host              string   `yaml:"host"`
42		Count             int      `yaml:"count"`
43		Labels            []string `yaml:"labels"`
44		Mode              string   `yaml:"mode"`
45		Profile           string   `yaml:"profile"`
46		Ephemeral         bool     `yaml:"ephemeral"`
47		DockerNetworkMode string   `yaml:"docker_network_mode"` // bridge (default) or host; only for docker-mode Linux runners
48		// DockerCapAdd lists Linux capability names passed to docker run --cap-add (e.g. NET_ADMIN for gh-aw AWF iptables).
49		DockerCapAdd []string `yaml:"docker_cap_add"`
50		// DockerPreSetup is a bash script that runs inside the container before the runner starts.
51		// Use this to install tools needed for your workflows (e.g., Node.js for awf).
52		DockerPreSetup string `yaml:"docker_pre_setup"`
53	}
54	
55	// Scope returns "repo" or "org" depending on how the runner is registered.
56	func (rc *RunnerConfig) Scope() string {
57		if rc.Org != "" {
58			return "org"
59		}
60		return "repo"
61	}
62	
63	// ScopeTarget returns the repo (owner/repo) or org name used for GitHub API calls.
64	func (rc *RunnerConfig) ScopeTarget() string {
65		if rc.Org != "" {
66			return rc.Org
67		}
68		return rc.Repo
69	}
70	
71	// IsAgentic reports whether the runner uses the agentic workflow profile.
72	func (rc *RunnerConfig) IsAgentic() bool {
73		return strings.EqualFold(strings.TrimSpace(rc.Profile), "agentic")
74	}
75	
76	func (rc *RunnerConfig) EffectiveMode(hostOS string) string {
77		if rc.Mode != "" {
78			return rc.Mode
79		}
80		if hostOS == "linux" {
81			return "docker"
82		}
83		return "native"
84	}
85	
86	// EffectiveDockerNetworkMode returns bridge or host for docker run --network.
87	// Only docker-mode runners may use host; everything else resolves to bridge.
88	func (rc *RunnerConfig) EffectiveDockerNetworkMode(hostOS string) string {
89		if rc.EffectiveMode(hostOS) != "docker" {
90			return "bridge"
91		}
92		switch strings.ToLower(strings.TrimSpace(rc.DockerNetworkMode)) {
93		case "host":
94			return "host"
95		default:
96			return "bridge"
97		}
98	}
99	
100	// DefaultLabels generates standard GitHub Actions labels based on mode, host OS, and arch.
101	// Docker-mode runners always report as Linux regardless of host OS.
102	func DefaultLabels(mode, hostOS, arch string) []string {
103		labels := []string{"self-hosted"}
104	
105		osLabel := ""
106		switch mode {
107		case "docker":
108			osLabel = "Linux"
109		default:
110			switch hostOS {
111			case "linux":
112				osLabel = "Linux"
113			case "darwin":
114				osLabel = "macOS"
115			case "windows":
116				osLabel = "Windows"
117			}
118		}
119		if osLabel != "" {
120			labels = append(labels, osLabel)
121		}
122	
123		archLabel := ""
124		switch arch {
125		case "amd64":
126			archLabel = "X64"
127		case "arm64":
128			archLabel = "ARM64"
129		}
130		if archLabel != "" {
131			labels = append(labels, archLabel)
132		}
133	
134		return labels
135	}
136	
137	// EffectiveLabels returns the runner's labels, auto-generating them from host info if empty.
138	// Agentic-profile runners automatically get a "gh-aw" label appended.
139	func (rc *RunnerConfig) EffectiveLabels(hostOS, arch string) []string {
140		var labels []string
141		if len(rc.Labels) > 0 {
142			labels = rc.Labels
143		} else {
144			mode := rc.EffectiveMode(hostOS)
145			labels = DefaultLabels(mode, hostOS, arch)
146		}
147		if rc.IsAgentic() && !hasLabel(labels, "gh-aw") {
148			labels = append(labels, "gh-aw")
149		}
150		return labels
151	}
152	
153	func hasLabel(labels []string, target string) bool {
154		for _, l := range labels {
155			if strings.EqualFold(l, target) {
156				return true
157			}
158		}
159		return false
160	}
161	
162	func (rc *RunnerConfig) InstanceNames() []string {
163		count := rc.Count
164		if count < 1 {
165			count = 1
166		}
167		names := make([]string, count)
168		for i := range count {
169			names[i] = fmt.Sprintf("%s-%d", rc.Name, i+1)
170		}
171		return names
172	}
173	
174	func Load(path string) (*Config, error) {
175		data, err := os.ReadFile(path)
176		if err != nil {
177			return nil, fmt.Errorf("reading config: %w", err)
178		}
179	
180		var cfg Config
181		if err := yaml.Unmarshal(data, &cfg); err != nil {
182			return nil, fmt.Errorf("parsing config: %w", err)
183		}
184	
185		cfg.resolveEnvRefs()
186		cfg.applyDefaults()
187	
188		if err := cfg.Validate(); err != nil {
189			return nil, err
190		}
191	
192		return &cfg, nil
193	}
194	
195	func (c *Config) resolveEnvRefs() {
196		c.GitHub.PAT = resolveEnv(c.GitHub.PAT)
197	}
198	
199	func resolveEnv(val string) string {
200		if strings.HasPrefix(val, "env:") {
201			envVar := strings.TrimPrefix(val, "env:")
202			return os.Getenv(envVar)
203		}
204		return val
205	}
206	
207	func normalizeArch(goarch string) string {
208		switch goarch {
209		case "amd64", "arm64":
210			return goarch
211		default:
212			return goarch
213		}
214	}
215	
216	func (c *Config) applyDefaults() {
217		for name, h := range c.Hosts {
218			if IsLocalAddr(h.Addr) {
219				if h.OS == "" {
220					h.OS = runtime.GOOS
221				}
222				if h.Arch == "" {
223					h.Arch = normalizeArch(runtime.GOARCH)
224				}
225				c.Hosts[name] = h
226			}
227		}
228		for i := range c.Runners {
229			if c.Runners[i].Count < 1 {
230				c.Runners[i].Count = 1
231			}
232			c.Runners[i].applyAgenticDefaults()
233		}
234	}
235	
236	// applyAgenticDefaults fills in the Docker configuration implied by profile: agentic.
237	func (rc *RunnerConfig) applyAgenticDefaults() {
238		if !rc.IsAgentic() {
239			return
240		}
241		if rc.Mode == "" {
242			rc.Mode = "docker"
243		}
244		if rc.DockerNetworkMode == "" {
245			rc.DockerNetworkMode = "host"
246		}
247		if !hasCapability(rc.DockerCapAdd, "NET_ADMIN") {
248			rc.DockerCapAdd = append(rc.DockerCapAdd, "NET_ADMIN")
249		}
250	}
251	
252	func hasCapability(caps []string, target string) bool {
253		for _, c := range caps {
254			if strings.EqualFold(c, target) {
255				return true
256			}
257		}
258		return false
259	}
260	
261	func (c *Config) Validate() error {
262		if c.GitHub.PAT != "" {
263			return fmt.Errorf("github.pat is no longer supported; remove it from runners.yml and authenticate with `gh auth login`")
264		}
265	
266		if len(c.Hosts) == 0 {
267			return fmt.Errorf("at least one host must be defined")
268		}
269	
270		for name, h := range c.Hosts {
271			if h.Addr == "" {
272				return fmt.Errorf("host %q: addr is required (use \"local\" for the current machine)", name)
273			}
274			// os and arch may be empty for remote hosts -- they are auto-detected over SSH before operations.
275			if h.OS != "" {
276				switch h.OS {
277				case "linux", "darwin", "windows":
278				default:
279					return fmt.Errorf("host %q: os must be linux, darwin, or windows (got %q)", name, h.OS)
280				}
281			}
282			if h.Arch != "" {
283				switch h.Arch {
284				case "amd64", "arm64":
285				default:
286					return fmt.Errorf("host %q: arch must be amd64 or arm64 (got %q)", name, h.Arch)
287				}
288			}
289			if h.WindowsPS != "" {
290				if h.OS != "" && h.OS != "windows" {
291					return fmt.Errorf("host %q: windows_ps is only valid when os is windows", name)
292				}
293				switch strings.ToLower(strings.TrimSpace(h.WindowsPS)) {
294				case "powershell", "pwsh":
295				default:
296					return fmt.Errorf("host %q: windows_ps must be powershell or pwsh (got %q)", name, h.WindowsPS)
297				}
298			}
299			if h.DockerSocket != "" {
300				if h.OS != "" && h.OS != "linux" && h.OS != "darwin" {
301					return fmt.Errorf("host %q: docker_socket is only supported on Linux and macOS hosts", name)
302				}
303				if !strings.HasPrefix(h.DockerSocket, "/") {
304					return fmt.Errorf("host %q: docker_socket must be an absolute path (got %q)", name, h.DockerSocket)
305				}
306			}
307		}
308	
309		if len(c.Runners) == 0 {
310			return fmt.Errorf("at least one runner must be defined")
311		}
312	
313		for _, r := range c.Runners {
314			if r.Name == "" {
315				return fmt.Errorf("runner name is required")
316			}
317			if r.Repo == "" && r.Org == "" {
318				return fmt.Errorf("runner %q: repo or org is required", r.Name)
319			}
320			if r.Repo != "" && r.Org != "" {
321				return fmt.Errorf("runner %q: specify repo or org, not both", r.Name)
322			}
323			if r.Group != "" && r.Org == "" {
324				return fmt.Errorf("runner %q: group requires org (runner groups are organization-level)", r.Name)
325			}
326			if r.Host == "" {
327				return fmt.Errorf("runner %q: host is required", r.Name)
328			}
329			hcfg, ok := c.Hosts[r.Host]
330			if !ok {
331				return fmt.Errorf("runner %q: host %q not found in hosts", r.Name, r.Host)
332			}
333			if r.Profile != "" && !strings.EqualFold(r.Profile, "agentic") {
334				return fmt.Errorf("runner %q: profile must be 'agentic' (got %q)", r.Name, r.Profile)
335			}
336			if r.IsAgentic() && r.Mode == "native" {
337				return fmt.Errorf("runner %q: profile 'agentic' requires docker mode (AWF sandbox needs Docker)", r.Name)
338			}
339			if r.Mode != "" && r.Mode != "docker" && r.Mode != "native" {
340				return fmt.Errorf("runner %q: mode must be 'docker' or 'native' (got %q)", r.Name, r.Mode)
341			}
342			netMode := strings.ToLower(strings.TrimSpace(r.DockerNetworkMode))
343			if netMode != "" && netMode != "bridge" && netMode != "host" {
344				return fmt.Errorf("runner %q: docker_network_mode must be 'bridge' or 'host' (got %q)", r.Name, r.DockerNetworkMode)
345			}
346			if netMode != "" {
347				if r.EffectiveMode(hcfg.OS) != "docker" {
348					return fmt.Errorf("runner %q: docker_network_mode applies only when mode is docker", r.Name)
349				}
350			}
351			if err := validateDockerCapAdd(&r, hcfg.OS); err != nil {
352				return err
353			}
354		}
355	
356		return nil
357	}
358	
359	func validateDockerCapAdd(r *RunnerConfig, hostOS string) error {
360		if len(r.DockerCapAdd) == 0 {
361			return nil
362		}
363		if r.EffectiveMode(hostOS) != "docker" {
364			return fmt.Errorf("runner %q: docker_cap_add applies only when mode is docker", r.Name)
365		}
366		for _, cap := range r.DockerCapAdd {
367			c := strings.TrimSpace(cap)
368			if c == "" {
369				return fmt.Errorf("runner %q: docker_cap_add contains an empty entry", r.Name)
370			}
371			if c != cap {
372				return fmt.Errorf("runner %q: docker_cap_add entries must not have leading or trailing spaces (got %q)", r.Name, cap)
373			}
374			for _, ch := range c {
375				isLetter := (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')
376				isDigit := ch >= '0' && ch <= '9'
377				if !isLetter && !isDigit && ch != '_' {
378					return fmt.Errorf("runner %q: docker_cap_add invalid capability name %q (use letters, digits, underscore only)", r.Name, c)
379				}
380			}
381		}
382		return nil
383	}
384	
385	// NeedsDetection reports whether any host is missing os or arch (and is not local).
386	func (c *Config) NeedsDetection() bool {
387		for _, h := range c.Hosts {
388			if !IsLocalAddr(h.Addr) && (h.OS == "" || h.Arch == "") {
389				return true
390			}
391		}
392		return false
393	}
394	
395	func (c *Config) RunnersForHost(hostName string) []RunnerConfig {
396		var result []RunnerConfig
397		for _, r := range c.Runners {
398			if r.Host == hostName {
399				result = append(result, r)
400			}
401		}
402		return result
403	}
404	
405	func (c *Config) RunnersForRepo(repo string) []RunnerConfig {
406		var result []RunnerConfig
407		for _, r := range c.Runners {
408			if r.Repo == repo {
409				result = append(result, r)
410			}
411		}
412		return result
413	}
414	
415	func (c *Config) UniqueRepos() []string {
416		seen := map[string]bool{}
417		var repos []string
418		for _, r := range c.Runners {
419			if r.Repo == "" {
420				continue
421			}
422			if !seen[r.Repo] {
423				seen[r.Repo] = true
424				repos = append(repos, r.Repo)
425			}
426		}
427		return repos
428	}
429	
430	func (c *Config) UniqueOrgs() []string {
431		seen := map[string]bool{}
432		var orgs []string
433		for _, r := range c.Runners {
434			if r.Org == "" {
435				continue
436			}
437			if !seen[r.Org] {
438				seen[r.Org] = true
439				orgs = append(orgs, r.Org)
440			}
441		}
442		return orgs
443	}
444	
445	func (c *Config) FindRunner(name string) (*RunnerConfig, bool) {
446		for i := range c.Runners {
447			if c.Runners[i].Name == name {
448				return &c.Runners[i], true
449			}
450			for _, inst := range c.Runners[i].InstanceNames() {
451				if inst == name {
452					return &c.Runners[i], true
453				}
454			}
455		}
456		return nil, false
457	}
458	
459	// ResolveRunnerInstance maps a CLI argument (base name or instance) to the instance directory name (e.g. myapp-1).
460	func (rc *RunnerConfig) ResolveRunnerInstance(nameArg string) (string, error) {
461		for _, inst := range rc.InstanceNames() {
462			if inst == nameArg {
463				return inst, nil
464			}
465		}
466		if rc.Name == nameArg {
467			names := rc.InstanceNames()
468			if len(names) != 1 {
469				return "", fmt.Errorf("runner %q has %d instances; specify one of: %s", rc.Name, len(names), strings.Join(names, ", "))
470			}
471			return names[0], nil
472		}
473		return "", fmt.Errorf("runner %q: %q is not a valid name or instance", rc.Name, nameArg)
474	}
475	
476	// FindRunnerForLogs resolves a runner by base or instance name. If hostFilter is non-empty, only that host's runner block matches.
477	// Returns an error when nothing matches or when multiple hosts match the same name without a host filter.
478	func (c *Config) FindRunnerForLogs(nameArg, hostFilter string) (*RunnerConfig, error) {
479		var matches []*RunnerConfig
480		seen := map[*RunnerConfig]bool{}
481		for i := range c.Runners {
482			r := &c.Runners[i]
483			if hostFilter != "" && r.Host != hostFilter {
484				continue
485			}
486			matched := false
487			if r.Name == nameArg {
488				matched = true
489			} else {
490				for _, inst := range r.InstanceNames() {
491					if inst == nameArg {
492						matched = true
493						break
494					}
495				}
496			}
497			if matched && !seen[r] {
498				seen[r] = true
499				matches = append(matches, r)
500			}
501		}
502		if len(matches) == 0 {
503			if hostFilter != "" {
504				return nil, fmt.Errorf("runner %q not found for host %q", nameArg, hostFilter)
505			}
506			return nil, fmt.Errorf("runner %q not found in config", nameArg)
507		}
508		if len(matches) > 1 {
509			hosts := make([]string, 0, len(matches))
510			for _, r := range matches {
511				hosts = append(hosts, r.Host)
512			}
513			return nil, fmt.Errorf("runner %q matches multiple hosts %v; specify --host", nameArg, hosts)
514		}
515		return matches[0], nil
516	}
517	
518	// FilterRunners returns runners matching optional host, repo, and/or explicit runner/instance names.
519	func FilterRunners(cfg *Config, hostFilter, repoFilter string, nameArgs []string) []RunnerConfig {
520		runners := cfg.Runners
521	
522		if hostFilter != "" {
523			var filtered []RunnerConfig
524			for _, r := range runners {
525				if r.Host == hostFilter {
526					filtered = append(filtered, r)
527				}
528			}
529			runners = filtered
530		}
531	
532		if repoFilter != "" {
533			var filtered []RunnerConfig
534			for _, r := range runners {
535				if r.Repo == repoFilter {
536					filtered = append(filtered, r)
537				}
538			}
539			runners = filtered
540		}
541	
542		if len(nameArgs) > 0 {
543			nameSet := map[string]bool{}
544			for _, a := range nameArgs {
545				nameSet[a] = true
546			}
547			var filtered []RunnerConfig
548			for _, r := range runners {
549				if nameSet[r.Name] {
550					filtered = append(filtered, r)
551					continue
552				}
553				for _, inst := range r.InstanceNames() {
554					if nameSet[inst] {
555						filtered = append(filtered, r)
556						break
557					}
558				}
559			}
560			runners = filtered
561		}
562	
563		return runners
564	}
