package setup

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/an-lee/gh-sr/internal/config"
)

// LibraryScriptsDir is the directory containing built-in script YAML files.
var LibraryScriptsDir = func() string {
	exe, err := os.Executable()
	if err != nil {
		return "./internal/runner/setup/scripts"
	}
	dir := filepath.Dir(exe)
	// For development, check relative path first
	if _, err := os.Stat(filepath.Join(dir, "internal", "runner", "setup", "scripts")); err == nil {
		return filepath.Join(dir, "internal", "runner", "setup", "scripts")
	}
	// For release, check relative to exe
	return filepath.Join(dir, "scripts")
}()

// LibraryScript represents a script definition loaded from the library.
type LibraryScript struct {
	Name           string            `yaml:"name"`
	Description    string            `yaml:"description"`
	Version        string            `yaml:"version"`         // schema version
	DefaultVersion string            `yaml:"default_version"` // default version if not specified
	Tools          []string          `yaml:"tools"`           // list of tools installed
	OSVariants     map[string]map[string]string `yaml:"os_variants"` // OS -> version -> script
}

// AvailableVersions returns all available versions for a given OS.
func (s *LibraryScript) AvailableVersions(osName string) []string {
	if variants, ok := s.OSVariants[osName]; ok {
		versions := make([]string, 0, len(variants))
		for v := range variants {
			versions = append(versions, v)
		}
		return versions
	}
	return nil
}

// GetScript returns the script for the given OS and version.
// If version is empty, uses the default version.
func (s *LibraryScript) GetScript(osName, version string) (string, error) {
	if version == "" {
		version = s.DefaultVersion
	}

	variants, ok := s.OSVariants[osName]
	if !ok {
		return "", fmt.Errorf("script %q has no variants for OS %q", s.Name, osName)
	}

	script, ok := variants[version]
	if !ok {
		return "", fmt.Errorf("script %q has no version %q for OS %q (available: %v)", s.Name, version, osName, variants)
	}

	return script, nil
}

// Loader loads and validates library scripts.
type Loader struct {
	scripts map[string]*LibraryScript
}

// NewLoader creates a new script loader.
func NewLoader() (*Loader, error) {
	l := &Loader{
		scripts: make(map[string]*LibraryScript),
	}

	entries, err := os.ReadDir(LibraryScriptsDir)
	if err != nil {
		return nil, fmt.Errorf("reading script library dir: %w", err)
	}

	for _, entry := range entries {
		if entry.IsDir() || filepath.Ext(entry.Name()) != ".yaml" {
			continue
		}

		script, err := loadScriptFile(filepath.Join(LibraryScriptsDir, entry.Name()))
		if err != nil {
			return nil, fmt.Errorf("loading script %q: %w", entry.Name(), err)
		}

		if err := validateScript(script); err != nil {
			return nil, fmt.Errorf("validating script %q: %w", script.Name, err)
		}

		l.scripts[script.Name] = script
	}

	return l, nil
}

// Get returns a library script by name.
func (l *Loader) Get(name string) (*LibraryScript, bool) {
	s, ok := l.scripts[name]
	return s, ok
}

// List returns all available library scripts.
func (l *Loader) List() []*LibraryScript {
	scripts := make([]*LibraryScript, 0, len(l.scripts))
	for _, s := range l.scripts {
		scripts = append(scripts, s)
	}
	return scripts
}

// ComposePreSetup composes a full pre-setup script from the config.
func ComposePreSetup(cfg *config.PreSetupConfig, dockerPreSetup string, osName string, loader *Loader) (string, error) {
	var parts []string

	// Handle legacy DockerPreSetup as an inline script
	if dockerPreSetup != "" && (cfg == nil || len(cfg.Scripts) == 0) {
		return dockerPreSetup, nil
	}

	if cfg == nil {
		return "", nil
	}

	for i, s := range cfg.Scripts {
		count := 0
		if s.Library != "" {
			count++
		}
		if s.Inline != "" {
			count++
		}
		if s.Remote != "" {
			count++
		}
		if count != 1 {
			return "", fmt.Errorf("script at index %d: exactly one of library, inline, or remote must be set", i)
		}

		if s.Library != "" {
			script, err := loader.Get(s.Library)
			if err != nil {
				return "", fmt.Errorf("loading library script %q: %w", s.Library, err)
			}
			if script == nil {
				return "", fmt.Errorf("library script %q not found", s.Library)
			}
			scriptContent, err := script.GetScript(osName, s.Version)
			if err != nil {
				return "", fmt.Errorf("getting script %q for OS %q: %w", s.Library, osName, err)
			}
			parts = append(parts, scriptContent)
		} else if s.Inline != "" {
			parts = append(parts, s.Inline)
		} else if s.Remote != "" {
			script, err := FetchRemoteScript(s.Remote)
			if err != nil {
				return "", fmt.Errorf("fetching remote script %q: %w", s.Remote, err)
			}
			parts = append(parts, script)
		}
	}

	// Append legacy DockerPreSetup if both old and new are present
	if dockerPreSetup != "" && len(cfg.Scripts) > 0 {
		parts = append(parts, dockerPreSetup)
	}

	return joinScripts(parts), nil
}

func joinScripts(parts []string) string {
	if len(parts) == 0 {
		return ""
	}
	result := parts[0]
	for i := 1; i < len(parts); i++ {
		result += "\n && \\\n" + parts[i]
	}
	return result
}

