package setup

import (
	"fmt"
	"os"

	"gopkg.in/yaml.v3"
)

func loadScriptFile(path string) (*LibraryScript, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading file: %w", err)
	}

	var script LibraryScript
	if err := yaml.Unmarshal(data, &script); err != nil {
		return nil, fmt.Errorf("parsing YAML: %w", err)
	}

	return &script, nil
}

func validateScript(s *LibraryScript) error {
	if s.Name == "" {
		return fmt.Errorf("name is required")
	}
	if s.DefaultVersion == "" {
		return fmt.Errorf("default_version is required for script %q", s.Name)
	}
	if len(s.OSVariants) == 0 {
		return fmt.Errorf("script %q must have at least one os_variant", s.Name)
	}

	for osName, versions := range s.OSVariants {
		if osName != "linux" && osName != "darwin" && osName != "windows" {
			return fmt.Errorf("script %q: unknown OS %q (must be linux, darwin, or windows)", s.Name, osName)
		}
		if len(versions) == 0 {
			return fmt.Errorf("script %q: OS %q must have at least one version", s.Name, osName)
		}

		// Check that default version exists
		if _, ok := versions[s.DefaultVersion]; !ok {
			return fmt.Errorf("script %q: default_version %q not found in OS %q variants", s.Name, s.DefaultVersion, osName)
		}

		for version, script := range versions {
			if script == "" {
				return fmt.Errorf("script %q: empty script for OS %q version %q", s.Name, osName, version)
			}
		}
	}

	return nil
}

