// It caches the result to avoid repeated network calls.
func FetchRemoteScript(url string) (string, error) {
	cacheKey := cacheKey(url)
	cachePath := filepath.Join(CacheDir, cacheKey)

	// Try cache first
	if data, err := os.ReadFile(cachePath); err == nil {
		return string(data), nil
	}

	// Fetch from network
	client := &http.Client{Timeout: 30 * time.Second}
	req, err := http.NewRequest(http.MethodGet, url, nil)
	if err != nil {
		return "", fmt.Errorf("creating request: %w", err)
	}
	req.Header.Set("Accept", "application/x-yaml, text/yaml, text/plain")

	resp, err := client.Do(req)
	if err != nil {
		return "", fmt.Errorf("fetching %q: %w", url, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("fetching %q: HTTP %d", url, resp.StatusCode)
	}

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("reading response: %w", err)
	}

	// Try to parse as a script YAML first
	var script LibraryScript
	if err := yaml.Unmarshal(data, &script); err == nil {
		// It's a full script YAML, extract the default version for linux
		if scriptContent, err := script.GetScript("linux", ""); err == nil {
			// Cache the script content
			if err := os.MkdirAll(CacheDir, 0755); err == nil {
				os.WriteFile(cachePath, []byte(scriptContent), 0644)
			}
			return scriptContent, nil
		}
		// If no linux default, return the whole content
		return string(data), nil
	}

	// Treat as raw script content
	if err := os.MkdirAll(CacheDir, 0755); err == nil {
		os.WriteFile(cachePath, data, 0644)
	}

	return string(data), nil
}

func cacheKey(url string) string {
	hash := sha256.Sum256([]byte(url))
	return hex.EncodeToString(hash[:8]) + ".sh"
}

