			if r.Status == "offline" {
				if err := m.GitHub.DeleteRunnerScoped(key.scope, key.target, r.ID); err != nil {
					return removed, fmt.Errorf("deleting runner %s (id=%d): %w", r.Name, r.ID, err)
				}
				removed++
			}
		}
	}
	return removed, nil
}

