199	func runQuickInit(runnersPath string, force bool) error {
200		scanner := bufio.NewScanner(os.Stdin)
201		prompt := func(label, defaultVal string) string {
202			if defaultVal != "" {
203				fmt.Printf("%s [%s]: ", label, defaultVal)
204			} else {
205				fmt.Printf("%s: ", label)
206			}
207			if scanner.Scan() {
208				v := strings.TrimSpace(scanner.Text())
209				if v != "" {
210					return v
211				}
212			}
213			return defaultVal
214		}
215	
216		fmt.Println("=== gh sr quick setup ===")
217		fmt.Println("This will create a working config. OS, arch, mode, and labels are all auto-detected.")
218		fmt.Println()
219	
220		repo := prompt("GitHub repo (owner/repo)", "")
221		if repo == "" {
222			return fmt.Errorf("repo is required")
223		}
224		if !strings.Contains(repo, "/") {
225			return fmt.Errorf("repo must be in owner/repo format")
226		}
227	
228		addr := prompt("SSH address of runner host (user@host, or 'local' for this machine)", "local")
229	
230		hostName := "runner-host"
231		if config.IsLocalAddr(addr) {
232			hostName = "local"
233		} else {
234			parts := strings.SplitN(addr, "@", 2)
235			if len(parts) == 2 {
236				h := strings.Split(parts[1], ":")[0]
237				h = strings.ReplaceAll(h, ".", "-")
238				if h != "" {
239					hostName = h
240				}
241			}
242		}
243	
244		baseName := strings.ReplaceAll(strings.Split(repo, "/")[1], ".", "-")
245		runnerName := baseName + "-" + hostName
246	
247		countStr := prompt("Number of runner instances", "1")
248		count := 1
249		if _, err := fmt.Sscanf(countStr, "%d", &count); err != nil || count < 1 {
250			count = 1
251		}
252	
253		agenticAnswer := prompt("Use GitHub Agentic Workflows (gh-aw) profile? (y/n)", "n")
254		agentic := strings.ToLower(strings.TrimSpace(agenticAnswer)) == "y"
255	
256		var profileLine string
257		if agentic {
258			profileLine = "\n    profile: agentic"
259		}
260	
261		seed := fmt.Sprintf(`github: {}
262	hosts:
263	  %s:
264	    addr: %s
265	runners:
266	  - name: %s
267	    repo: %s
268	    host: %s
269	    count: %d%s
270	`, hostName, addr, runnerName, repo, hostName, count, profileLine)
271	
272		if _, err := os.Stat(runnersPath); err == nil && !force {
273			fmt.Printf("\n%s already exists. Overwrite? [y/N]: ", runnersPath)
274			if scanner.Scan() {
275				if strings.ToLower(strings.TrimSpace(scanner.Text())) != "y" {
276					fmt.Println("Aborted.")
277					return nil
278				}
279			}
280		}
281	
282		if err := os.WriteFile(runnersPath, []byte(seed), 0o600); err != nil {
283			return err
284		}
285		fmt.Printf("\nWrote %s\n", runnersPath)
286	
287		// Validate the generated config loads.
288		if _, err := config.Load(runnersPath); err != nil {
289			return fmt.Errorf("generated config is invalid: %w", err)
290		}
291	
292		fmt.Println()
293		fmt.Println("Config generated! Summary:")
294		fmt.Printf("  Host:   %s (%s)\n", hostName, addr)
295		fmt.Printf("  Runner: %s -> %s (x%d)\n", runnerName, repo, count)
296		if agentic {
297			fmt.Println("  Profile: agentic (docker, host network, NET_ADMIN, gh-aw label)")
298		} else {
299			fmt.Println("  Mode:   auto-detected at runtime")
300		}
301		fmt.Println("  Labels: auto-generated from host os/arch")
302		fmt.Println()
303		fmt.Println("Next steps:")
304		fmt.Println("  gh sr doctor   # verify config, GitHub access, and host connectivity")
305		fmt.Println("  gh sr up       # setup + start runners (all in one)")
306		fmt.Println()
307		fmt.Println("Authentication: run `gh auth login`.")
308	
309		return nil
310	}
