430	func doctorCmd() *cobra.Command {
431		var strict bool
432		cmd := &cobra.Command{
433			Use:   "doctor",
434			Short: "Check config, GitHub API access, and host prerequisites",
435			Long:  "Validates local paths, configuration, GitHub API access, and SSH targets (Docker or native tooling per runner mode). See README \"Host setup\" for steps gh sr cannot automate.",
436			RunE: func(cmd *cobra.Command, args []string) error {
437				if err := config.BootstrapEnv(); err != nil {
438					return err
439				}
440				cfgPath, err := config.ResolveConfigPath(cfgFile)
441				if err != nil {
442					return err
443				}
444				envPath, err := config.EnvFilePath()
445				if err != nil {
446					return err
447				}
448	
449				cfg, cfgErr := config.LoadFromPath(cfgPath)
450				var gh *runner.GitHubClient
451				hasGitHubToken := false
452				if cfg != nil {
453					tok, tokErr := config.ResolveToken(cfg)
454					if tokErr == nil {
455						gh = runner.NewGitHubClient(tok)
456						hasGitHubToken = true
457					}
458				}
459	
460				res := doctor.Run(cmd.OutOrStdout(), cfgPath, envPath, cfg, cfgErr, gh, hasGitHubToken, filterHost, filterRepo, strict)
461				if code := doctor.ExitCode(res, strict); code != 0 {
462					os.Exit(code)
463				}
464				return nil
465			},
466		}
