func setupScriptsShowCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "show [name[@version]]",
		Short: "Show details of a pre-setup script",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			loader, err := setup.NewLoader()
			if err != nil {
				return fmt.Errorf("loading scripts: %w", err)
			}

			name, version := parseScriptRef(args[0])
			script, ok := loader.Get(name)
			if !ok {
				return fmt.Errorf("script %q not found; use 'gh sr setup scripts list' to see available scripts", name)
			}

			fmt.Printf("Name:        %s\n", script.Name)
			fmt.Printf("Description: %s\n", script.Description)
			fmt.Printf("Default:     %s\n", script.DefaultVersion)
			fmt.Println()
			fmt.Println("Tools:")
			for _, t := range script.Tools {
				fmt.Printf("  - %s\n", t)
			}
			fmt.Println()

			// Show versions for each OS
			for osName, versions := range script.OSVariants {
				fmt.Printf("Versions for %s: %s\n", osName, strings.Join(sortedKeys(versions), ", "))
			}
			fmt.Println()

			// Show the script content for the requested version (default to linux)
			targetVersion := version
			if targetVersion == "" {
				targetVersion = script.DefaultVersion
			}
			scriptContent, err := script.GetScript("linux", targetVersion)
			if err != nil {
				return fmt.Errorf("getting script content: %w", err)
			}
			fmt.Printf("Script content (linux, %s):\n", targetVersion)
			fmt.Println("```bash")
			fmt.Println(scriptContent)
			fmt.Println("```")
			return nil
		},
	}
}

func setupScriptsSearchCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "search <query>",
		Short: "Search pre-setup scripts by tool or description",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			loader, err := setup.NewLoader()
			if err != nil {
				return fmt.Errorf("loading scripts: %w", err)
			}

			query := strings.ToLower(args[0])
			scripts := loader.List()
			var matches []*setup.LibraryScript

			for _, s := range scripts {
				if strings.Contains(strings.ToLower(s.Name), query) {
					matches = append(matches, s)
					continue
				}
				if strings.Contains(strings.ToLower(s.Description), query) {
					matches = append(matches, s)
					continue
				}
				for _, t := range s.Tools {
					if strings.Contains(strings.ToLower(t), query) {
						matches = append(matches, s)
						break
					}
				}
			}

			if len(matches) == 0 {
				fmt.Printf("No scripts found matching %q.\n", query)
				return nil
			}

			fmt.Printf("Scripts matching %q:\n\n", query)
			for _, s := range matches {
				fmt.Printf("  %-12s %s\n", s.Name+":", s.Description)
			}
			return nil
		},
	}
}

func parseScriptRef(ref string) (name, version string) {
	if strings.Contains(ref, "@") {
		parts := strings.SplitN(ref, "@", 2)
		return parts[0], parts[1]
	}
	if strings.Contains(ref, ":") {
		// Support name:version format as well
		parts := strings.SplitN(ref, ":", 2)
		return parts[0], parts[1]
	}
	return ref, ""
}

func sortedKeys(m map[string]string) []string {
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	return keys
}

