			}

			if len(matches) == 0 {
				fmt.Printf("No scripts found matching %q.\n", query)
				return nil
			}

			fmt.Printf("Scripts matching %q:\n\n", query)
			for _, s := range matches {
				fmt.Printf("  %-12s %s\n", s.Name+":", s.Description)
			}
			return nil
		},
	}
}

func parseScriptRef(ref string) (name, version string) {
	if strings.Contains(ref, "@") {
		parts := strings.SplitN(ref, "@", 2)
		return parts[0], parts[1]
	}
	if strings.Contains(ref, ":") {
		// Support name:version format as well
		parts := strings.SplitN(ref, ":", 2)
		return parts[0], parts[1]
	}
	return ref, ""
}

func sortedKeys(m map[string]string) []string {
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	return keys
}

