package setup

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/an-lee/gh-sr/internal/config"
)

// LibraryScriptsDir is the directory containing built-in script YAML files.
var LibraryScriptsDir = func() string {
	// Check for development mode: if there's a go.mod in a parent directory,
	// we're likely running from source via `go run`
	dir, err := os.Getwd()
	if err == nil {
		for {
			if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
				scriptDir := filepath.Join(dir, "internal", "runner", "setup", "scripts")
				if _, err := os.Stat(scriptDir); err == nil {
					return scriptDir
				}
			}
			parent := filepath.Dir(dir)
			if parent == dir {
				break
			}
			dir = parent
		}
	}

	// Fallback: try executable-based paths
	exe, err := os.Executable()
	if err != nil {
		return "./internal/runner/setup/scripts"
	}
	exeDir := filepath.Dir(exe)

	// Check if running from a temp directory (e.g., `go run`)
	if strings.Contains(exeDir, "go-build") {
		return "./internal/runner/setup/scripts"
	}

	// For release: scripts are bundled alongside the binary
	releaseDir := filepath.Join(exeDir, "scripts")
	if _, err := os.Stat(releaseDir); err == nil {
		return releaseDir
	}

	// Fallback for development
	return "./internal/runner/setup/scripts"
}()

