+		parts := strings.SplitN(ref, "@", 2)
+		return parts[0], parts[1]
+	}
+	if strings.Contains(ref, ":") {
+		// Support name:version format as well
+		parts := strings.SplitN(ref, ":", 2)
+		return parts[0], parts[1]
+	}
+	return ref, ""
+}
+
